import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'
import { describe, expect, it } from 'vitest'

describe('preset-wind4 important option bug', () => {
  it('should work with important selector and text color', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#__nuxt',
          preflights: { reset: false },
        }),
      ],
    })

    const { css } = await uno.generate('text-red')

    // Check that the CSS is generated correctly
    expect(css).toContain('color:')
    expect(css).toContain('var(--un-text-opacity)')

    // Check that the selector includes the important wrapper
    expect(css).toContain('#__nuxt')

    console.log('Generated CSS:', css)
  })

  it('should generate property definition with important selector', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#__nuxt',
          preflights: { reset: false },
        }),
      ],
    })

    const { getLayer } = await uno.generate('text-red')

    const propertiesLayer = getLayer('properties')
    const defaultLayer = getLayer('default')

    console.log('Properties layer:', propertiesLayer)
    console.log('Default layer:', defaultLayer)

    // The properties layer should define --un-text-opacity
    expect(propertiesLayer).toContain('--un-text-opacity')

    // The default layer should use var(--un-text-opacity)
    expect(defaultLayer).toContain('var(--un-text-opacity)')

    // The default layer should have the important selector wrapper
    expect(defaultLayer).toContain('#__nuxt')
  })
})

