import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'
import { describe, expect, it } from 'vitest'

describe('preset-wind4 important option with opacity', () => {
  it('should handle text-opacity with important selector', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#__nuxt',
          preflights: { reset: false },
        }),
      ],
    })

    const { getLayer } = await uno.generate('text-red text-opacity-50')

    const propertiesLayer = getLayer('properties')
    const defaultLayer = getLayer('default')

    // The @property rule should NOT have the important selector wrapper
    expect(propertiesLayer).toContain('@property --un-text-opacity')
    expect(propertiesLayer).not.toContain('#__nuxt :is(@property')

    // The actual utilities should have the important selector wrapper
    expect(defaultLayer).toContain('#__nuxt :is(.text-red)')
    expect(defaultLayer).toContain('#__nuxt :is(.text-opacity-50)')
  })

  it('should handle bg-opacity with important selector', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#app',
          preflights: { reset: false },
        }),
      ],
    })

    const { getLayer } = await uno.generate('bg-blue-500 bg-opacity-75')

    const propertiesLayer = getLayer('properties')
    const defaultLayer = getLayer('default')

    // The @property rule should NOT have the important selector wrapper
    expect(propertiesLayer).toContain('@property --un-bg-opacity')
    expect(propertiesLayer).not.toContain('#app :is(@property')

    // The actual utilities should have the important selector wrapper
    expect(defaultLayer).toContain('#app :is(.bg-blue-500)')
    expect(defaultLayer).toContain('#app :is(.bg-opacity-75)')
  })

  it('should handle border-opacity with important selector', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#root',
          preflights: { reset: false },
        }),
      ],
    })

    const { getLayer } = await uno.generate('border-red-500 border-opacity-50')

    const propertiesLayer = getLayer('properties')
    const defaultLayer = getLayer('default')

    // The @property rule should NOT have the important selector wrapper
    expect(propertiesLayer).toContain('@property --un-border-opacity')
    expect(propertiesLayer).not.toContain('#root :is(@property')

    // The actual utilities should have the important selector wrapper
    expect(defaultLayer).toContain('#root :is(.border-red-500)')
    expect(defaultLayer).toContain('#root :is(.border-opacity-50)')
  })

  it('should work correctly with important: true (boolean)', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: true,
          preflights: { reset: false },
        }),
      ],
    })

    const { css } = await uno.generate('text-red')

    // When important is true, it should add !important to properties
    expect(css).toContain('color:color-mix')
    expect(css).toContain('!important')

    // The @property should not have !important
    expect(css).toContain('@property --un-text-opacity')
    expect(css).not.toMatch(/@property.*!important/)
  })

  it('should handle text-stroke-opacity with important selector', async () => {
    const uno = await createGenerator({
      envMode: 'dev',
      presets: [
        presetWind4({
          important: '#__nuxt',
          preflights: { reset: false },
        }),
      ],
    })

    const { getLayer } = await uno.generate('text-stroke-red text-stroke-opacity-50')

    const propertiesLayer = getLayer('properties')
    const defaultLayer = getLayer('default')

    // The @property rule should NOT have the important selector wrapper
    if (propertiesLayer.includes('@property --un-text-stroke-opacity')) {
      expect(propertiesLayer).toContain('@property --un-text-stroke-opacity')
      expect(propertiesLayer).not.toContain('#__nuxt :is(@property')
    }

    // The actual utilities should have the important selector wrapper
    expect(defaultLayer).toContain('#__nuxt')
  })
})

