import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'
import { describe, expect, it } from 'vitest'

describe('Bug reproduction: important selector with text-red', () => {
  it('should correctly generate CSS for text-red with important: "#__nuxt"', async () => {
    const uno = await createGenerator({
      presets: [
        presetWind4({
          important: '#__nuxt',
        }),
      ],
    })

    const { css, getLayer } = await uno.generate('text-red')

    // Verify the complete CSS output
    console.log('=== Full CSS Output ===')
    console.log(css)

    // Properties layer should have @property at root level
    const propertiesLayer = getLayer('properties')
    console.log('\n=== Properties Layer ===')
    console.log(propertiesLayer)

    // Should NOT wrap @property with the selector
    expect(propertiesLayer).toMatch(/@property --un-text-opacity/)
    expect(propertiesLayer).not.toMatch(/#__nuxt :is\(@property/)

    // Default layer should have the selector wrapper
    const defaultLayer = getLayer('default')
    console.log('\n=== Default Layer ===')
    console.log(defaultLayer)

    expect(defaultLayer).toMatch(/#__nuxt :is\(.text-red\)/)
    expect(defaultLayer).toContain('var(--un-text-opacity)')

    // Verify the property definition has the correct structure
    expect(propertiesLayer).toMatch(/@property --un-text-opacity\s*{\s*syntax:"<percentage>"/)
    expect(propertiesLayer).toMatch(/initial-value:\s*100%/)
  })

  it('should work with color opacity inline syntax', async () => {
    const uno = await createGenerator({
      presets: [
        presetWind4({
          important: '#__nuxt',
        }),
      ],
    })

    const { css } = await uno.generate('text-red/50')

    console.log('=== CSS for text-red/50 ===')
    console.log(css)

    // Should contain the opacity value
    expect(css).toMatch(/#__nuxt :is\(.text-red\/50\)/)
    expect(css).toContain('color-mix')
  })

  it('should work with multiple color utilities', async () => {
    const uno = await createGenerator({
      presets: [
        presetWind4({
          important: '#__nuxt',
        }),
      ],
    })

    const { css } = await uno.generate('text-red bg-blue-500 border-green-300')

    console.log('=== CSS for multiple colors ===')
    console.log(css)

    // All utilities should have the selector wrapper
    expect(css).toMatch(/#__nuxt :is\(.text-red\)/)
    expect(css).toMatch(/#__nuxt :is\(.bg-blue-500\)/)
    expect(css).toMatch(/#__nuxt :is\(.border-green-300\)/)

    // All @property definitions should be at root level
    expect(css).toMatch(/@property --un-text-opacity/)
    expect(css).toMatch(/@property --un-bg-opacity/)
    expect(css).toMatch(/@property --un-border-opacity/)

    // None of the @property definitions should have the selector wrapper
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-text-opacity\)/)
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-bg-opacity\)/)
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-border-opacity\)/)
  })
})

