    expect(css).toMatch(/@property --un-text-opacity/)
    expect(css).toMatch(/@property --un-bg-opacity/)
    expect(css).toMatch(/@property --un-border-opacity/)

    // None of the @property definitions should have the selector wrapper
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-text-opacity\)/)
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-bg-opacity\)/)
    expect(css).not.toMatch(/#__nuxt :is\(@property --un-border-opacity\)/)
  })
})

