import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'
import { describe, expect, it } from 'vitest'

describe('Bug reproduction: important selector with text-red', () => {
  it('should correctly generate CSS for text-red with important: "#__nuxt"', async () => {
    const uno = await createGenerator({
      presets: [
        presetWind4({
          important: '#__nuxt',
        }),
      ],
    })

    const { css, getLayer } = await uno.generate('text-red')

    // Verify the complete CSS output
    console.log('=== Full CSS Output ===')
    console.log(css)

    // Properties layer should have @property at root level
    const propertiesLayer = getLayer('properties')
    console.log('\n=== Properties Layer ===')
    console.log(propertiesLayer)

    // Should NOT wrap @property with the selector
    expect(propertiesLayer).toMatch(/@property --un-text-opacity/)
    expect(propertiesLayer).not.toMatch(/#__nuxt :is\(@property/)

    // Default layer should have the selector wrapper
    const defaultLayer = getLayer('default')
    console.log('\n=== Default Layer ===')
    console.log(defaultLayer)

    expect(defaultLayer).toMatch(/#__nuxt :is\(.text-red\)/)
    expect(defaultLayer).toContain('var(--un-text-opacity)')

