// Quick test to verify the bug is fixed
const { createGenerator } = require('@unocss/core')
const presetWind4 = require('@unocss/preset-wind4').default

async function test() {
  console.log('Testing the fix for: important selector with text-red causing undefined --un-text-opacity\n')

  const uno = await createGenerator({
    envMode: 'dev',
    presets: [
      presetWind4({
        important: '#__nuxt',
        preflights: { reset: false },
      }),
    ],
  })

  const { css, getLayer } = await uno.generate('text-red')

  console.log('=== Properties Layer ===')
  const propertiesLayer = getLayer('properties')
  console.log(propertiesLayer)
  console.log()

  console.log('=== Default Layer ===')
  const defaultLayer = getLayer('default')
  console.log(defaultLayer)
  console.log()

  // Verify the fix
  const hasCorrectPropertyDefinition = propertiesLayer.includes('@property --un-text-opacity') &&
                                       !propertiesLayer.includes('#__nuxt :is(@property')
  const hasCorrectSelector = defaultLayer.includes('#__nuxt :is(.text-red)')
  const usesTextOpacity = defaultLayer.includes('var(--un-text-opacity)')

  console.log('=== Verification ===')
  console.log('✓ @property definition at root level (not wrapped):', hasCorrectPropertyDefinition ? '✓ PASS' : '✗ FAIL')
  console.log('✓ Utility selector wrapped with #__nuxt :is():', hasCorrectSelector ? '✓ PASS' : '✗ FAIL')
  console.log('✓ Uses var(--un-text-opacity) correctly:', usesTextOpacity ? '✓ PASS' : '✗ FAIL')

  if (hasCorrectPropertyDefinition && hasCorrectSelector && usesTextOpacity) {
    console.log('\n🎉 All checks passed! The bug is fixed!')
    process.exit(0)
  } else {
    console.log('\n❌ Some checks failed!')
    process.exit(1)
  }
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

